module srt_divider (  
    input [15:0] obf_dividend,  
    input [15:0] divisor,  
    output reg [15:0] quotient,  
    output reg [15:0] remainder  
);  
    always @(*) begin  
        if (divisor == 0) begin  
            quotient = 0;  
            remainder = obf_dividend;  
        end else begin  
            // SRT division algorithm simplified for illustration purposes  
            quotient = obf_dividend / divisor;  
            remainder = obf_dividend % divisor;  
        end  
    end  
endmodule
